import (
	"errors"
	"fmt"

	apierrors "k8s.io/apimachinery/pkg/api/errors"
	"k8s.io/apimachinery/pkg/runtime/schema"
)

const (
	resourceGroup               = "agentcube.volcano.sh"
	sessionResourceName         = "sessions"
	agentRuntimeResourceName    = "agentruntimes"
	codeInterpreterResourceName = "codeinterpreters"
)

var (
	ErrAgentRuntimeNotFound    = errors.New("agent runtime not found")
	ErrCodeInterpreterNotFound = errors.New("code interpreter not found")
	ErrTemplateMissing         = errors.New("resource has no pod template")
	ErrPublicKeyMissing        = errors.New("public key not yet loaded from Router Secret")
	ErrNotFound                = errors.New("store: not found")
)

// NewSessionNotFoundError creates an API status error for session not found
func NewSessionNotFoundError(sessionID string) error {
	return apierrors.NewNotFound(
		schema.GroupResource{Group: resourceGroup, Resource: sessionResourceName},
		sessionID,
	)
}

// NewSandboxTemplateNotFoundError creates an error for sandbox template not found
func NewSandboxTemplateNotFoundError(namespace, name, kind string) error {
	resource := agentRuntimeResourceName
	if kind == "CodeInterpreter" {
		resource = codeInterpreterResourceName
	}
	return apierrors.NewNotFound(
		schema.GroupResource{Group: resourceGroup, Resource: resource},
		name,
	)
}

// NewUpstreamUnavailableError creates an error for upstream unavailable
func NewUpstreamUnavailableError(err error) error {
	return fmt.Errorf("upstream unavailable: %w", err)
}

// NewInternalError creates an internal server error
func NewInternalError(err error) error {
	return fmt.Errorf("internal server error: %w", err)
}

