package store

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"strconv"
	"strings"
	"sync"
	"time"

	"github.com/redis/go-redis/v9"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

const (
	sessionKeyPrefix      = "session:"
	sessionExpiryKey      = "session:expiry"
	sessionLastActivityKey = "session:last_activity"
)

var (
	initOnce   sync.Once
	storeStore Store
)

// Storage returns the singleton store instance
func Storage() Store {
	initOnce.Do(func() {
		storeStore = initStore()
	})
	return storeStore
}

func initStore() Store {
	storeType := strings.ToLower(os.Getenv("STORE_TYPE"))
	if storeType == "" {
		storeType = "redis"
	}

	switch storeType {
	case "redis":
		return newRedisStore()
	case "valkey":
		return newValkeyStore()
	default:
		klog.Fatalf("unsupported store type: %s", storeType)
		return nil
	}
}

// RedisStore implements Store using Redis
type RedisStore struct {
	client *redis.Client
}

func newRedisStore() *RedisStore {
	addr := os.Getenv("REDIS_ADDR")
	if addr == "" {
		klog.Fatal("REDIS_ADDR environment variable is not set")
	}

	password := os.Getenv("REDIS_PASSWORD")
	passwordRequired := true
	if v := os.Getenv("REDIS_PASSWORD_REQUIRED"); v != "" {
		passwordRequired, _ = strconv.ParseBool(strings.ToLower(v))
	}

	if passwordRequired && password == "" {
		klog.Fatal("REDIS_PASSWORD is required but not set")
	}

	client := redis.NewClient(&redis.Options{
		Addr:     addr,
		Password: password,
		DB:       0,
	})

	return &RedisStore{client: client}
}

func (s *RedisStore) Ping(ctx context.Context) error {
	result, err := s.client.Ping(ctx).Result()
	if err != nil {
		return err
	}
	if result != "PONG" {
		return fmt.Errorf("unexpected ping response: %s", result)
	}
	return nil
}

func (s *RedisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := sessionKeyPrefix + sessionID
	data, err := s.client.Get(ctx, key).Result()
	if err == redis.Nil {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, err
	}

	var info types.SandboxInfo
	if err := json.Unmarshal([]byte(data), &info); err != nil {
		return nil, err
	}
	return &info, nil
}

func (s *RedisStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox is nil")
	}
	if sandbox.ExpiresAt.IsZero() {
		return errors.New("sandbox ExpiresAt is zero")
	}

	key := sessionKeyPrefix + sandbox.SessionID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	pipe := s.client.Pipeline()
	pipe.SetNX(ctx, key, data, 0)
	pipe.ZAdd(ctx, sessionExpiryKey, redis.Z{
		Score:  float64(sandbox.ExpiresAt.Unix()),
		Member: sandbox.SessionID,
	})
	pipe.ZAdd(ctx, sessionLastActivityKey, redis.Z{
		Score:  float64(time.Now().Unix()),
		Member: sandbox.SessionID,
	})

	_, err = pipe.Exec(ctx)
	return err
}

func (s *RedisStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox is nil")
	}

	key := sessionKeyPrefix + sandbox.SessionID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	// Use XX to ensure key exists
	result, err := s.client.SetXX(ctx, key, data, 0).Result()
	if err != nil {
		return err
	}
	if !result {
		return errors.New("key not exists")
	}
	return nil
}

func (s *RedisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := sessionKeyPrefix + sessionID

	pipe := s.client.Pipeline()
	pipe.Del(ctx, key)
	pipe.ZRem(ctx, sessionExpiryKey, sessionID)
	pipe.ZRem(ctx, sessionLastActivityKey, sessionID)

	_, err := pipe.Exec(ctx)
	return err
}

func (s *RedisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	return s.listSandboxesByZSet(ctx, sessionExpiryKey, 0, before.Unix(), limit)
}

func (s *RedisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	return s.listSandboxesByZSet(ctx, sessionLastActivityKey, 0, before.Unix(), limit)
}

func (s *RedisStore) listSandboxesByZSet(ctx context.Context, zsetKey string, min, max int64, limit int64) ([]*types.SandboxInfo, error) {
	ids, err := s.client.ZRangeByScore(ctx, zsetKey, &redis.ZRangeBy{
		Min:   fmt.Sprintf("%d", min),
		Max:   fmt.Sprintf("%d", max),
		Count: limit,
	}).Result()
	if err != nil {
		return nil, err
	}

	if len(ids) == 0 {
		return []*types.SandboxInfo{}, nil
	}

	// Get all session data
	keys := make([]string, len(ids))
	for i, id := range ids {
		keys[i] = sessionKeyPrefix + id
	}

	results, err := s.client.MGet(ctx, keys...).Result()
	if err != nil {
		return nil, err
	}

	sandboxes := make([]*types.SandboxInfo, 0, len(results))
	for i, result := range results {
		if result == nil {
			continue
		}
		data, ok := result.(string)
		if !ok {
			continue
		}
		var info types.SandboxInfo
		if err := json.Unmarshal([]byte(data), &info); err != nil {
			klog.Warningf("failed to unmarshal sandbox %s: %v", ids[i], err)
			continue
		}
		sandboxes = append(sandboxes, &info)
	}

	return sandboxes, nil
}

func (s *RedisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return errors.New("sessionID is empty")
	}

	key := sessionKeyPrefix + sessionID
	exists, err := s.client.Exists(ctx, key).Result()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	if at.IsZero() {
		at = time.Now()
	}

	return s.client.ZAdd(ctx, sessionLastActivityKey, redis.Z{
		Score:  float64(at.Unix()),
		Member: sessionID,
	}).Err()
}

func (s *RedisStore) Close() error {
	return s.client.Close()
}

var ErrNotFound = errors.New("store: not found")

