package picod

import (
	"bytes"
	"context"
	"crypto/rsa"
	"crypto/x509"
	"encoding/base64"
	"encoding/pem"
	"fmt"
	"mime"
	"net/http"
	"os"
	"path/filepath"
	"strconv"
	"strings"
	"sync"
	"time"


	"github.com/gin-gonic/"in"
	"github.com/golang-/jwt/v5"
)

const (
	TimeoutExitCode   = 124
	MaxBodySize     = 32 << 20 // 32 MiB
	PublicKeyEnvVar = "PICOD_AUTH_PUBLIC_KEY"
	maxFileMode    = 0777
)

type Config struct {
	Port      int    `json:"port"`
	Workspace string `json:"workspace"`
}

type Server struct {
	engine       *gin.Engine
	config     Config
	authManager *AuthManager
	startTime   time.Time
	workspaceDir string
}

type AuthManager struct {
	publicKey *rsa.PublicKey
	mutex     sync.RWMutex
}

type ExecuteRequest struct {
	Command    []string          `json:"command" binding:"required"`
	Timeout    string          `json:"timeout"`
	WorkingDir string        `json:"working_dir"`
	Env        map[string]string `json:"env"`
}

type ExecuteResponse struct {
	Stdout    string    `json:"stdout"`
	Stderr    string    `json:"stderr"`
	ExitCode  int       `json:"exit_code"`
	Duration  float64   `json:"duration"`
	StartTime time.Time `json:"start_time"`
	EndTime   time.Time `json:"end_time"`
}

type FileInfo struct {
	Path     string    `json:"path"`
	Size     int64   `json:"size"`
	Mode     string  `json:"mode"`
	Modified time.Time `json:"modified"`
}

type UploadFileRequest struct {
	Path    string `json:"path" binding:"required"`
	Content string `json:"content" binding:"required"`
	Mode    string `json:"mode"`
}

type FileEntry struct {
	Name     string    `json:"name"`
	Size     int64   `json:"size"`
	Modified time.Time `json:"modified"`
	Mode     string  `json:"mode"`
	IsDir    bool    `json:"is_dir"`
}

type ListFilesResponse struct {
	Files []FileEntry `json:"files"`
}

func NewServer(config Config) (*Server, error) {
	gin.SetMode(gin.ReleaseMode)
	engine := gin.New()
	engine.Use(gin.Logger(), gin.Recovery())

	server := &Server{
		config:    config,
		engine:    engine,
		startTime: time.Now(),
	}


	// Resolve workspace
	if config.Workspace != "" {
		absPath, err := filepath.Abs(config.Workspace)
		if err != nil {
			server.workspaceDir = config.Workspace
		} else {
			server.workspaceDir = absPath
		}
	} else {
		cwd, err := os.Getwd()
		if err != nil {
			return nil, fmt.Errorf("failed to get current working directory: %w", err)
		}
		server.workspaceDir = cwd
	}

	// Initialize auth manager
	server.authManager = &AuthManager{}
	if err := server.authManager.LoadPublicKeyFromEnv(); err != nil {
		return nil, fmt.Errorf("failed to load public key: %w", err)
	}

	// Register routes
	api := engine.Group("/api")
	api.Use(server.authManager.AuthMiddleware())
	{
		api.POST("/execute", server.ExecuteHandler)
		api.POST("/files", server.UploadFileHandler)
		api.GET("/files", server.ListFilesHandler)
		api.GET("/files/*path", server.DownloadFileHandler)
	}
	engine.GET("/health", server.HealthCheckHandler)

	return server, nil
}

func (am *AuthManager) LoadPublicKeyFromEnv() error {
	keyData := os.Getenv(PublicKeyEnvVar)
	if keyData == "" {
		return fmt.Errorf("environment variable %s is not set", PublicKeyEnvVar)
	}

	block, _ := pem.Decode([]byte(keyData))
	if block == nil {
		return fmt.Errorf("failed to decode PEM block")
	}

	key, err := x509.ParsePKIXPublicKey(block.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse public key: %w", err)
	}


	publicKey, ok := key.(*rsa.PublicKey)
	if !ok {
		return fmt.Errorf("key is not RSA public key")
	}

	am.mutex.Lock()
	am.publicKey = publicKey
	am.mutex.Unlock()
	return nil
}

func (am *AuthManager) AuthMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.JSON(http.StatusUnauthorized, gin.H{
					"error":  "missing authorization header",
					"code":   http.StatusUnauthorized,
					"detail": "JWT token required",
				})
			c.Abort()
			return
		}

		parts := strings.Split(authHeader, " ")
		if len(parts) != 2 || parts[0] != "Bearer" {
			c.JSON(http.StatusUnauthorized, gin.H{
					"error":  "invalid authorization format",
					"code":   http.StatusUnauthorized,
					"detail": "Use Bearer <token>",
				})
			c.Abort()
			return
		}

		tokenString := parts[1]
		token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
			if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
				return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
			}
			am.mutex.RLock()
			defer am.mutex.RUnlock()
			return am.publicKey, nil
		}, jwt.WithExpirationRequired(), jwt.WithIssuedAt(), jwt.WithLeeway(time.Minute))

		if err != nil || !token.Valid {
			c.JSON(http.StatusUnauthorized, gin.H{
					"error":  "Invalid token",
					"code":   http.StatusUnauthorized,
					"detail": err.Error(),
				})
			c.Abort()
			return
		}

		c.Request.Body = http.MaxBytesReader(c.Writer, c.Request.Body, MaxBodySize)
		c.Next()
	}
}

